urlset:

  {{ base }}/
  {{ today }}
  hourly
  1.0


  {{ base }}/annonces/
  {{ today }}
  hourly
  0.9


  {{ base }}/rubriques/
  {{ today }}
  daily
  0.8

{% for cat in categories_sitemap %}

  {{ base }}/annonces/?categorie={{ cat.code }}
  {{ today }}
  daily
  0.8

{% endfor %}
{% for sp in static_pages %}

  {{ base }}{{ sp.path }}
  {{ today }}
  {{ sp.changefreq }}
  {{ sp.priority }}

{% endfor %}
{% for annonce in annonces %}

  {{ base }}/annonces/{{ annonce.pk }}/
  {{ annonce.updated_at|date:"Y-m-d" }}
  weekly
  0.6

{% endfor %}
